<?php
namespace App\Http\Controllers\Api; use App\Http\Controllers\Controller; use App\Models\Member; use Illuminate\Http\Request;
class MemberController extends Controller { public function index(){return response()->json(['data'=>Member::with('user')->get()]);} public function store(Request $r){return response()->json(['data'=>Member::create($r->validate(['game_id'=>'required|exists:games,id','user_id'=>'required|exists:users,id']))],201);} public function show(Member $member){return response()->json(['data'=>$member->load('user')]);} public function update(Request $r,Member $member){$member->update($r->validate(['game_id'=>'sometimes|exists:games,id','user_id'=>'sometimes|exists:users,id']));return response()->json(['data'=>$member]);} public function destroy(Member $member){$member->delete();return response()->noContent();} }
